var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀과 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"어이, 방 꼬락서니가 이게 뭐야? 무슨 경사라도 났어?","JPN":"ちょっと、この部屋は何？　お祝いパーティーでもするつもり？","ENG":"Hey, what’s going on with this room? Is there some kind of party or something?","TWN":"喂，這房間是怎麼回事？有什麼喜事發生嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"집어치워. 고작 계약서 한 장 쓰는 걸로 호들갑을 이렇게 떨어? 우리 사이에.","JPN":"やめなよ。たかが契約書1枚ではしゃぐな。そんな間柄でもないじゃん。","ENG":"Knock it off. Making such a fuss over just signing a contract between us?","TWN":"別瞎鬧，就簽個契約而已，至於這麼大驚小怪嗎？以我們的關係還需要這樣嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"누가 보면 혼약이라도 맺는 줄 알겠어?","JPN":"はたから見れば、結婚でもするのかって思われるだろ？","ENG":"Someone might think we’re getting engaged or something.","TWN":"別人看到還以為是要簽結婚證書咧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"뭐… 나는 아직 어리니까. 당장은 아니더라도 대충 10년 뒤에는 생각해 볼게.","JPN":"まあ……アタシはまだ子どもだし。すぐには無理だけど、10年くらい後だったら考えてはみる。","ENG":"Well... I’m still young, so maybe I’ll consider it in about ten years. But not anytime soon.","TWN":"嗯…我現在還小。雖然現在無法答應你，但10年後我會考慮看看的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"뭘 그딴 눈으로 쳐다봐? 프로포즈 처음 봐?","JPN":"なんだよその目は。プロポーズも知らないのか？","ENG":"Why are you looking at me like that? Haven’t you ever seen a proposal before.","TWN":"幹嘛用那種眼神看我？沒看過人家求婚喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"애초에 난 총각이 꽤 마음에 들거든? 성격이나 취향 같은 건 조금씩 맞춰가면 되잖아.","JPN":"そもそもアタシはお兄さんが結構気に入ったんだ。性格とか趣味とか、ちょっとずつ合わせて行けばいいんだし。","ENG":"Honestly, I quite like you, Bucko. We can work on aligning our personalities and preferences over time, right?","TWN":"我本來就蠻喜歡你的。至於個性和興趣方面，是可以慢慢磨合的嘛。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"그러니까 어른이 돼서 환속하면, 그땐 색시로 삼아주는 거다?","JPN":"だから大人になって還俗したら、お嫁にしてよね。","ENG":"So, when I grow up and leave this life behind, you’ll take me as your bride then?","TWN":"所以等我長大還俗後，就當你的新娘吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"뭐야, 그 아빠 미소는? 죽고 싶어?","JPN":"なんだよ、そのパパみたいな笑顔は？　死にたいのか？","ENG":"Why are you staring at me, smiling like a dad? You got a death wish or something?","TWN":"你那父愛的笑是怎麼回事？想找死？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"흥, 넬슨한테 들었다고. 어른이라면 자기가 뱉은 말은 끝까지 책임져야 한다면서?","JPN":"ふん、ネルソンに聞いたんだ。大人なら自分の言葉に責任を持たないとダメだって。","ENG":"Hmph, I heard it from Nelson. If you’re an adult, you have to take full responsibility for your words, right?","TWN":"哼，尼爾森說，成年人得對自己的承諾負責。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"내가 어리다고, 어물쩡 빠져나갈 생각은 버리는 게 좋을 거야.","JPN":"アタシが幼いからって、適当に誤魔化そうとしない方がいいよ。","ENG":"You’d better not think you can weasel out of this just because I’m young.","TWN":"別以為我年紀小，你就能敷衍我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"이래봬도 내가 제법 끈질긴 편이거든.","JPN":"こう見えてもアタシ、結構しつこいから。","ENG":"For your information, I can be pretty persistent.","TWN":"我告訴你，我固執起來連我自己都會怕。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"자, 그러니 어서 손가락 걸고 약속해, 총각.","JPN":"はい、だから指切りして。","ENG":"So, come on, pinky promise with me, Bucko.","TWN":"快點，打勾勾說好囉，年輕人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"앞으로도 내 곁을 떠나지 않겠다고.","JPN":"これからもアタシのそばから離れないって。","ENG":"Promise that you’ll never leave my side.","TWN":"說你以後都不會離開我，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"쭉 같이 있겠다고.","JPN":"ずっと一緒にいるって。","ENG":"That you'll stay with me forever.","TWN":"一直陪著我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};